import React, { createContext, useState, useContext, useEffect } from 'react';

export const AuthContext = createContext();

export const useAuth = () => {
  return useContext(AuthContext);
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check if user is logged in from localStorage
    const storedUser = localStorage.getItem('mangauz_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setLoading(false);
  }, []);

  const login = async (email, password) => {
    // Mock login - in real app, this would be an API call
    let mockUser;
    
    // Admin foydalanuvchisi uchun maxsus email
    if (email === 'ruhiddinov03@gmail.com' && password === 'Behruz03') {
      mockUser = {
        id: 999,
        email,
        username: 'Admin',
        avatar: null,
        level: 10,
        points: 99999,
        role: 'admin'
      };
    } else {
      mockUser = {
        id: Date.now(),
        email,
        username: email.split('@')[0],
        avatar: null,
        level: 1,
        points: 100,
        role: 'user'
      };
    }
    
    setUser(mockUser);
    localStorage.setItem('mangauz_user', JSON.stringify(mockUser));
    return { success: true, user: mockUser };
  };

  const register = async (email, password, username) => {
    // Mock registration
    const newUser = {
      id: Date.now(),
      email,
      username,
      avatar: null,
      level: 1,
      points: 0,
      role: 'user'
    };
    
    setUser(newUser);
    localStorage.setItem('mangauz_user', JSON.stringify(newUser));
    return { success: true, user: newUser };
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('mangauz_user');
  };

  const isAdmin = () => {
    return user && user.role === 'admin';
  };

  const value = {
    user,
    login,
    register,
    logout,
    loading,
    isAdmin
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};
